// Extract ALL vCard URLs from PROPFIND response (no limit)
const xml = $input.first().json.data || '';

if (!xml || xml.length < 100) {
  throw new Error('Keine XML-Daten von CardDAV erhalten. Prüfe Credentials und Adressbuch-ID.');
}

// Namespace-agnostic regex for href with .vcf
const hrefRegex = /<(?:[dD]:)?href[^>]*>\s*([^<]*\.vcf)\s*<\/(?:[dD]:)?href>/gi;
const urls = [];
let match;

while ((match = hrefRegex.exec(xml)) !== null) {
  const url = match[1].trim();
  if (url) urls.push(url);
}

if (urls.length === 0) {
  throw new Error('Keine vCard-URLs gefunden. Prüfe CardDAV Credentials und Adressbuch-ID.');
}

console.log(`Found ${urls.length} contact URLs to sync`);

return urls.map(url => ({
  json: { contactUrl: url }
}));

// Parse vCard into structured JSON for PostgreSQL
const vCardText = $json.vCardData || $json.data || '';
const contactUrl = $('Parse Contact URLs').item.json.contactUrl || '';

if (!vCardText.includes('BEGIN:VCARD')) {
  return { _skip: true };
}

const lines = vCardText.split(/\r?\n/);
const contact = {
  full_name: '', first_name: '', last_name: '',
  phone_primary: '', phone_mobile: '', phone_work: '',
  email: '', cardav_uid: '', cardav_url: contactUrl
};

for (const line of lines) {
  if (line.startsWith('FN:')) {
    contact.full_name = line.substring(3).trim();
  }
  if (line.startsWith('N:')) {
    const parts = line.substring(2).split(';');
    contact.last_name = (parts[0] || '').trim();
    contact.first_name = (parts[1] || '').trim();
  }
  if (line.startsWith('TEL')) {
    const telMatch = line.match(/TEL[^:]*:(.+)/);
    if (telMatch) {
      const number = telMatch[1].trim();
      const typeMatch = line.match(/TYPE=([^;:]+)/);
      const type = typeMatch ? typeMatch[1].toUpperCase() : 'OTHER';
      if (type === 'CELL' || type === 'MOBILE') {
        contact.phone_mobile = contact.phone_mobile || number;
      } else if (type === 'WORK') {
        contact.phone_work = contact.phone_work || number;
      } else {
        contact.phone_primary = contact.phone_primary || number;
      }
    }
  }
  if (line.startsWith('EMAIL')) {
    const emailMatch = line.match(/EMAIL[^:]*:(.+)/);
    if (emailMatch) contact.email = contact.email || emailMatch[1].trim();
  }
  if (line.startsWith('UID:')) {
    contact.cardav_uid = line.substring(4).trim();
  }
}

// Fallback UID from URL
if (!contact.cardav_uid) {
  contact.cardav_uid = contactUrl.replace(/.*\//, '').replace('.vcf', '');
}

if (!contact.full_name && !contact.first_name) {
  return { _skip: true };
}

if (!contact.full_name) {
  contact.full_name = `${contact.first_name} ${contact.last_name}`.trim();
}

// Escape single quotes for SQL interpolation (prevents O'Brien etc. from breaking)
for (const key of Object.keys(contact)) {
  if (typeof contact[key] === 'string') {
    contact[key] = contact[key].replace(/'/g, "''");
  }
}

return contact;
